1999   MatrixTy getZeroMatrix(Type *EltType, unsigned R, unsigned C) {
2000     MatrixTy Res;
2001     auto *ColumType = FixedVectorType::get(EltType, R);
2002     for (unsigned I = 0; I < C; ++I)
2003       Res.addVector(ConstantAggregateZero::get(ColumType));
2004     return Res;
2005   }
