2066   void emitSIMDTiling(CallInst *MatMul, LoadInst *LoadOp0, LoadInst *LoadOp1,
2067                       StoreInst *Store,
2068                       SmallPtrSetImpl<Instruction *> &FusedInsts) {
2069     assert(MatrixLayout == MatrixLayoutTy::ColumnMajor &&
2070            "Tiling only supported for column-major matrixes at the moment!");
2071     if (!isFusionProfitable(MatMul))
2072       return;
2073 
2074     ShapeInfo LShape(MatMul->getArgOperand(2), MatMul->getArgOperand(3));
2075     ShapeInfo RShape(MatMul->getArgOperand(3), MatMul->getArgOperand(4));
2076 
2077     const unsigned R = LShape.NumRows;
2078     const unsigned C = RShape.NumColumns;
2079     const unsigned M = LShape.NumColumns;
2080     auto *EltType = cast<FixedVectorType>(MatMul->getType())->getElementType();
2081 
2082     Value *APtr = getNonAliasingPointer(LoadOp0, Store, MatMul);
2083     Value *BPtr = getNonAliasingPointer(LoadOp1, Store, MatMul);
2084     Value *CPtr = Store->getPointerOperand();
2085 
2086     // Use loop-based tiling when the number of expected operations exceeds
2087     // threshold.
2088     unsigned NumOps = getNumNativeVectorOps(EltType, R, M, C);
2089     bool UseLoops =
2090         (NumOps > TileLoopsThreshold) && R % TileSize == 0 && C % TileSize == 0;
2091     if (UseLoops)
2092       createTiledLoops(MatMul, APtr, LShape, BPtr, RShape, Store);
2093     else {
2094       IRBuilder<> Builder(Store);
2095       for (unsigned J = 0; J < C; J += TileSize)
2096         for (unsigned I = 0; I < R; I += TileSize) {
2097           const unsigned TileR = std::min(R - I, unsigned(TileSize));
2098           const unsigned TileC = std::min(C - J, unsigned(TileSize));
2099           MatrixTy Res = getZeroMatrix(EltType, TileR, TileC);
2100 
2101           for (unsigned K = 0; K < M; K += TileSize) {
2102             const unsigned TileM = std::min(M - K, unsigned(TileSize));
2103             MatrixTy A =
2104                 loadMatrix(APtr, LoadOp0->getAlign(), LoadOp0->isVolatile(),
2105                            LShape, getIndex(APtr, I), getIndex(APtr, K),
2106                            {TileR, TileM}, EltType, Builder);
2107             MatrixTy B =
2108                 loadMatrix(BPtr, LoadOp1->getAlign(), LoadOp1->isVolatile(),
2109                            RShape, getIndex(BPtr, K), getIndex(BPtr, J),
2110                            {TileM, TileC}, EltType, Builder);
2111             emitMatrixMultiply(Res, A, B, Builder, true, false,
2112                                getFastMathFlags(MatMul));
2113           }
2114           storeMatrix(Res, CPtr, Store->getAlign(), Store->isVolatile(), {R, M},
2115                       getIndex(CPtr, I), getIndex(CPtr, J), EltType, Builder);
2116         }
2117     }
2118 
2119     // Mark eliminated instructions as fused and remove them.
2120     FusedInsts.insert(Store);
2121     FusedInsts.insert(MatMul);
2122     eraseFromParentAndRemoveFromShapeMap(Store);
2123     eraseFromParentAndRemoveFromShapeMap(MatMul);
2124     if (LoadOp0->use_empty()) {
2125       FusedInsts.insert(LoadOp0);
2126       eraseFromParentAndRemoveFromShapeMap(LoadOp0);
2127     }
2128     if (LoadOp1 != LoadOp0 && LoadOp1->use_empty()) {
2129       FusedInsts.insert(LoadOp1);
2130       eraseFromParentAndRemoveFromShapeMap(LoadOp1);
2131     }
2132   }
