2007   void createTiledLoops(CallInst *MatMul, Value *LPtr, ShapeInfo LShape,
2008                         Value *RPtr, ShapeInfo RShape, StoreInst *Store) {
2009     auto *EltType = cast<FixedVectorType>(MatMul->getType())->getElementType();
2010 
2011     // Create the main tiling loop nest.
2012     TileInfo TI(LShape.NumRows, RShape.NumColumns, LShape.NumColumns, TileSize);
2013     DomTreeUpdater DTU(DT, DomTreeUpdater::UpdateStrategy::Lazy);
2014     Instruction *InsertI = cast<Instruction>(MatMul);
2015     BasicBlock *Start = InsertI->getParent();
2016     BasicBlock *End =
2017         SplitBlock(InsertI->getParent(), InsertI, DT, LI, nullptr, "continue");
2018     IRBuilder<> Builder(MatMul);
2019     BasicBlock *InnerBody = TI.CreateTiledLoops(Start, End, Builder, DTU, *LI);
2020 
2021     Type *TileVecTy =
2022         FixedVectorType::get(MatMul->getType()->getScalarType(), TileSize);
2023     MatrixTy TileResult;
2024     // Insert in the inner loop header.
2025     Builder.SetInsertPoint(TI.KLoop.Header->getTerminator());
2026     // Create PHI nodes for the result columns to accumulate across iterations.
2027     SmallVector<PHINode *, 4> ColumnPhis;
2028     for (unsigned I = 0; I < TileSize; I++) {
2029       auto *Phi = Builder.CreatePHI(TileVecTy, 2, "result.vec." + Twine(I));
2030       Phi->addIncoming(ConstantAggregateZero::get(TileVecTy),
2031                        TI.RowLoop.Header->getSingleSuccessor());
2032       TileResult.addVector(Phi);
2033       ColumnPhis.push_back(Phi);
2034     }
2035 
2036     // Insert in the inner loop body, which computes
2037     //   Res += Load(CurrentRow, K) * Load(K, CurrentColumn)
2038     Builder.SetInsertPoint(InnerBody->getTerminator());
2039     // Load tiles of the operands.
2040     MatrixTy A =
2041         loadMatrix(LPtr, {}, false, LShape, TI.RowLoop.Index, TI.KLoop.Index,
2042                    {TileSize, TileSize}, EltType, Builder);
2043     MatrixTy B =
2044         loadMatrix(RPtr, {}, false, RShape, TI.KLoop.Index, TI.ColumnLoop.Index,
2045                    {TileSize, TileSize}, EltType, Builder);
2046     emitMatrixMultiply(TileResult, A, B, Builder, true, false,
2047                        getFastMathFlags(MatMul));
2048     // Store result after the inner loop is done.
2049     Builder.SetInsertPoint(TI.RowLoop.Latch->getTerminator());
